        # Validate ownership & quantities without holding state lock too long
        # We'll re-validate at commit time as well.
        for item_id, qty in offer_items.items():
            qty = int(qty)
            if qty <= 0:
                return False, "invalid_qty"
            async with self._state_lock:
                it = self.items.get(item_id)
                if it is None:
                    return False, "item_not_found"
                if self.owner.get(item_id) != by:
                    return False, "not_owner"
                if qty > it.qty:
                    return False, "insufficient_qty"

        async with self._state_lock:
            t = self.trades.get(trade_id)
            if t is None:
                return False, "trade_not_found"
            if t.status != "open":
                return False, "trade_not_open"
            t.offers[by] = {str(k): int(v) for k, v in offer_items.items()}
            t.accepted.discard(t.a)
            t.accepted.discard(t.b)
            snapshot = {
                "type": "trade_updated",
                "trade_id": t.trade_id,
                "offers": t.offers,
                "accepted": list(t.accepted),
                "status": t.status,
            }
