    async def accept_trade(self, trade_id: str, by: str) -> Tuple[bool, str]:
        async with self._state_lock:
            t = self.trades.get(trade_id)
            if t is None:
                return False, "trade_not_found"
            if t.status != "open":
                return False, "trade_not_open"
            if by not in (t.a, t.b):
                return False, "not_participant"
            t.accepted.add(by)
